update project_signup
set status = '已通过'
where project_id = #{projectId} and user_id = #{userId}

update project_study
cover_path = #{coverPath}, theme = #{theme}, introduction = #{introduction}, content = #{content}, category = #{category}, capacity = #{capacity}, status = #{status}, update_time = #{updateTime}, like_count = #{likeCount}, click_count = #{clickCount},
where id = #{id}
